import crypto from "crypto"
import type { normalizeListing } from "../lib/sourcing/normalizeListing"

export function fingerprint(listing: normalizeListing): string {
  const data = {
    address: listing.address,
    city: listing.city,
    price: listing.price,
    sqft: listing.sqft,
    dom: listing.dom,                // ✅ DOM included
    status: listing.listingStatus,   // ✅ Status included
  }

  return crypto
    .createHash("sha256")
    .update(JSON.stringify(data))
    .digest("hex")
}
