import { detectNegativeFactors } from "./negativeRules"

export function evaluateProperty(listing: any) {
  const negatives = detectNegativeFactors(listing)

  let baseArv = Math.round(listing.price * 1.25)
  let adjustedArv = baseArv

  if (negatives.length === 1) {
    adjustedArv = Math.round(baseArv * 0.95)
  }

  if (negatives.length >= 2) {
    return {
      externalId: listing.externalId,
      address: listing.address,
      underwriting: {
        status: "FAIL",
        failureReasons: ["Multiple negative external factors"],
      },
      evaluatedAt: new Date().toISOString(),
    }
  }

  return {
    externalId: listing.externalId,
    address: listing.address,
    underwriting: {
      status: "PASS",
      arv: { baseArv, adjustedArv },
      negativeFactors: negatives,
    },
    evaluatedAt: new Date().toISOString(),
  }
}
