export function detectNegativeFactors(listing: any): string[] {
  const negatives: string[] = []

  if (listing.busyRoad) negatives.push("busy_road")
  if (listing.nearCommercial) negatives.push("commercial_proximity")
  if (listing.multifamilyNearby) negatives.push("multifamily_adjacent")

  return negatives
}
